import React, { useState, useEffect } from 'react';
import api from '../services/api';

function BalanceView({ refreshTrigger, onSettlementMade }) {
  const [balances, setBalances] = useState([]);
  const [suggestedPayments, setSuggestedPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showSettlement, setShowSettlement] = useState(false);
  const [selectedPayment, setSelectedPayment] = useState(null);
  const [settlementDate, setSettlementDate] = useState(new Date().toISOString().split('T')[0]);
  const [processingPayment, setProcessingPayment] = useState(false);

  useEffect(() => {
    loadBalances();
  }, [refreshTrigger]);

  const loadBalances = async () => {
    setLoading(true);
    try {
      const data = await api.getBalances();
      setBalances(data.balances);
      setSuggestedPayments(data.suggestedPayments || []);
    } catch (error) {
      console.error('Error loading balances:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSettlePayment = async (payment) => {
    if (processingPayment) {
      alert('Please wait, processing payment...');
      return;
    }

    setProcessingPayment(true);

    try {
      // Add the settlement
      await api.addSettlement({
        from_friend_id: payment.from,
        to_friend_id: payment.to,
        amount: payment.amount,
        date: settlementDate
      });
      
      alert(`✓ Payment recorded: ${payment.from_name} paid ${payment.to_name} $${payment.amount.toFixed(2)}`);
      
      // Close the modal
      setShowSettlement(false);
      setSelectedPayment(null);
      
      // Refresh balances immediately - this will remove the paid suggestion
      await loadBalances();
      
      // Notify parent component
      onSettlementMade();
      
    } catch (error) {
      console.error('Error recording settlement:', error);
      alert(error.response?.data?.error || 'Error recording settlement');
    } finally {
      setProcessingPayment(false);
    }
  };

  if (loading) {
    return <div>Loading balances...</div>;
  }

  return (
    <div>
      <h2>Current Balances</h2>
      
      <div className="card">
        <h3>Net Balances</h3>
        <p style={{ fontSize: '0.9em', color: '#666', marginBottom: '15px' }}>
          Positive = owed to you | Negative = you owe
        </p>
        {balances.map(person => (
          <div key={person.id} style={{ 
            display: 'flex', 
            justifyContent: 'space-between',
            padding: '10px',
            borderBottom: '1px solid #e0e0e0'
          }}>
            <span><strong>{person.name}</strong></span>
            <span className={
              person.balance > 0 ? 'balance-positive' : 
              person.balance < 0 ? 'balance-negative' : 'balance-neutral'
            }>
              {person.balance > 0 ? (
                <>+${person.balance.toFixed(2)} <span style={{ fontSize: '0.9em' }}>(owed to you)</span></>
              ) : person.balance < 0 ? (
                <>-${Math.abs(person.balance).toFixed(2)} <span style={{ fontSize: '0.9em' }}>(you owe)</span></>
              ) : (
                <>$0 <span style={{ fontSize: '0.9em' }}>(settled)</span></>
              )}
            </span>
          </div>
        ))}
      </div>

      {suggestedPayments.length > 0 ? (
        <div className="card">
          <h3>💰 Suggested Payments to Settle Up</h3>
          <p style={{ fontSize: '0.9em', color: '#666', marginBottom: '15px' }}>
            Click "Mark as Paid" after you've sent the money
          </p>
          {suggestedPayments.map((payment, index) => (
            <div key={index} style={{
              padding: '15px',
              margin: '10px 0',
              background: '#e8f4f8',
              borderRadius: '8px',
              borderLeft: '4px solid #10b981'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <span style={{ fontSize: '1.1em' }}>
                    <strong>{payment.from_name}</strong> → <strong>{payment.to_name}</strong>
                  </span>
                  <span className="balance-positive" style={{ marginLeft: '10px', fontSize: '1.2em' }}>
                    ${payment.amount.toFixed(2)}
                  </span>
                </div>
                <button 
                  onClick={() => {
                    setSelectedPayment(payment);
                    setShowSettlement(true);
                  }}
                  style={{ 
                    background: '#10b981', 
                    padding: '8px 16px',
                    margin: 0
                  }}
                  disabled={processingPayment}
                >
                  ✓ Mark as Paid
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="card" style={{ background: '#d1fae5', textAlign: 'center' }}>
          <h3>🎉 All Settled Up!</h3>
          <p>Everyone is paid up. No outstanding balances!</p>
        </div>
      )}

      {showSettlement && selectedPayment && (
        <div className="card" style={{ background: '#fff3cd', border: '2px solid #ffc107' }}>
          <h3>Confirm Payment</h3>
          <p style={{ fontSize: '1.1em' }}>
            <strong>{selectedPayment.from_name}</strong> is paying <strong>{selectedPayment.to_name}</strong>
          </p>
          <p className="balance-positive" style={{ fontSize: '1.3em' }}>
            Amount: ${selectedPayment.amount.toFixed(2)}
          </p>
          <div className="form-group">
            <label>Payment Date:</label>
            <input
              type="date"
              value={settlementDate}
              onChange={(e) => setSettlementDate(e.target.value)}
              style={{ width: '200px' }}
            />
          </div>
          <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
            <button 
              onClick={() => handleSettlePayment(selectedPayment)}
              disabled={processingPayment}
              style={{ background: '#10b981' }}
            >
              {processingPayment ? 'Processing...' : '✓ Confirm & Mark as Paid'}
            </button>
            <button 
              onClick={() => {
                setShowSettlement(false);
                setSelectedPayment(null);
              }} 
              style={{ background: '#6c757d' }}
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default BalanceView;
